<template lang="en">
<section>
    <loader :is-visible="isLoading"></loader>

    <tg-list :IsShowAction="true" ModuleName="RateSchedule" SubModuleCode="" :LegendArray="[]" :RenderRowActionMethod="renderActions" 
    @ActionButtonClick="actionButtonClick" :widgets="[]" IdentityColumn="RATE_SCHEDULE_ID" :listType="['List']" :ListData="RateScheduleData" 
    :HeaderData="Headers" :HeaderButtons="listheaderbuttons" :TotalRecords="TotalRecords" :SearchFields="leftSearchFields" IsSearchFieldsOnTop="true" 
    :ListDataCallBackFunction="FetchData" :showCheckBox="true" :SortExp="SortExp" :SortBy="SortBy" :NorecordfoundText="$t('NoRecordfound')" 
    :HeaderText="$t('RateSchedule')" @LeftsearchButtonClick="leftCommonSearch" @PagerButtonClick="pagerMethod" @HeaderButtonClick="commonHeaderButtonClick" 
    @SortdataButtonClick="sortdata" :routeInfo="$router">
        <template v-slot:slotdata="{ data }">                         
                <template v-if="data.column.COLUMN_NAME == 'Billing_Code'">                
                    <span>
                        <div class="text">
                            <span   :title="data.row.Billing_Code" class="">{{data.row.Billing_Code}}</span>
                        </div>
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'AMOUNT'">                
                    <span>
                        <a class="text Secondary" @click="EditAddRate(data.row.RATE_SCHEDULE_ID)">
                            <span :title="data.row.AMOUNT" class="primary">
                                {{ data.row.AMOUNT }}
                            </span>
                        </a>
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'START_DATE'">                
                    <span >
                        <div class="text">
                            <span   :title="data.row.START_DATE" class="">{{data.row.START_DATE}}</span>
                        </div>
                    </span>
                </template>
            <template v-if="data.column.COLUMN_NAME == 'END_DATE'">                
                <span >
                    <div class="text">
                        <span   :title="data.row.END_DATE" class="">{{data.row.END_DATE}}</span>
                    </div>
                </span>
            </template>
            <!-- CREATED_AT Column -->
            <template v-if="data.column.COLUMN_NAME === 'CREATED_AT'">
                <span>
                    {{ $options.filters.formatDateTime(data.row.CREATED_AT) }}
                </span>
            </template>

            <!-- MODIFIED_AT Column -->
            <template v-if="data.column.COLUMN_NAME === 'MODIFIED_AT'">
                <span>
                    {{ $options.filters.formatDateTime(data.row.MODIFIED_AT) }}
                </span>
            </template>

            <!-- STATUS Column -->
            <template v-if="data.column.COLUMN_NAME === 'STATUS'">
                <td class="text-center single-action">
                    <div class="cstm-drop-btn">
                        <select v-model="data.row.STATUS_ID" @change="UpdataStatus(data.row.STATUS_ID, data.row.RATE_SCHEDULE_ID)" 
                        :class="['ddlupdatestatus w-80',data.row.STATUS_ID == 1001 ? 'btn-success' : 'btn-danger']">
                            <option value="1001">{{ $t("Active") }}</option>
                            <option value="1002">{{ $t("Inactive") }}</option>
                        </select>
                    </div>
                </td>
            </template>
            <!-- New_Start_Date Column -->
            <template v-if="data.column.COLUMN_NAME === 'New_Start_Date'">
                <input type="text" class="form-control form-control-sm large-input" :value="data.row.New_Start_Date || ''" readonly />
            </template>

            <!-- New_End_Date Column -->
            <template v-if="data.column.COLUMN_NAME === 'New_End_Date'">
                <input type="text" class="form-control form-control-sm large-input" :value="data.row.New_End_Date || ''" readonly />
            </template>

            <!-- New_Rate Column -->
            <template v-if="data.column.COLUMN_NAME === 'New_Rate'">
                <input type="number" class="form-control form-control-sm large-input" v-model.number="data.row.New_Rate" min="0" step="0.01" />
            </template>

            <!-- New_Customer_Work_Code Column -->
            <template v-if="data.column.COLUMN_NAME === 'New_Customer_Work_Code'">
                <input type="text" class="form-control form-control-sm large-input" v-model.number="data.row.New_Customer_Work_Code"  />
            </template>
        </template>
    </tg-list>
    <div class="float-right mt-2" v-show="isShownCopyButton">
        <button class="btn btn-success mr-2" @click="UpdateCopyRateSchedule">
            <em class="fa fa-save pr-2"></em>
            {{ $t('update Rate Schedule') }}
        </button>
        <button class="btn btn-danger" @click="Cancel">
            {{ $t('Cancel') }}
        </button>
    </div>
   

    <!-- Modals/Components -->
    <AddRate v-if="isShowAddRate" :EditData="EditData" />
    <BulkUpdateRate v-if="isBulkUpdateRate" :EditData="EditData" />
    <Copy v-if="isCopyRate" :EditData="EditData" @navigateToSelected="openSelectedRecords"  :EditDataCopy="EditDataCopy" />
</section>
</template>

<script>
import AddRate from "./AddRate.vue";
import BulkUpdateRate from "./BulkUpdateRate.vue";
import Copy from "./Copy.vue";
import Schema from "../RateSchedule/Schema.js";
import DataService from "../../services/DataService.js";
import {locateBillingService} from "../../services/locateBillingService";
import * as XLSX from 'xlsx';

export default {
    components: {
        AddRate,
        BulkUpdateRate,
        Copy
    },
    data() {
        return {
            isLoading: false,
            isCopyRate: false,
            key: 0,
            UpdateRecord: false,
            isShownCopyButton: false,
            FormSchema: [],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Update Rate Schedule",
                    isVisible: true
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.FetchData
                }
            ],
            Headers: [{
                    "COLUMN_NAME": "CLIENT_NAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Contract',
                    "DISPLAY_ORDER": 1,
                },
                {
                    "COLUMN_NAME": "WORK_CODE",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Work Code',
                    "DISPLAY_ORDER": 2,
                },
                {
                    "COLUMN_NAME": "UTILITY_NAME",
                    "DATA_TYPE": "Date",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Utility Name',
                    "DISPLAY_ORDER": 3,
                },
                {
                    "COLUMN_NAME": "STATE_NAME",
                    "DATA_TYPE": "Date",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'State',
                    "DISPLAY_ORDER": 4,
                    settings: {
                        isInSlot: false
                    }
                },
                {
                    "COLUMN_NAME": "Billing_Code",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Customer Work Code',
                    "DISPLAY_ORDER": 5,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "AMOUNT",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Rate',
                    "DISPLAY_ORDER": 6,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "STATUS",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Status',
                    "DISPLAY_ORDER": 7,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "START_DATE",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Start Date',
                    "DISPLAY_ORDER": 8,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "END_DATE",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'End Date',
                    "DISPLAY_ORDER": 9,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "New_Customer_Work_Code",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": false,
                    "DISPLAY_NAME": this.$t('New Customer Work Code'),
                    "DISPLAY_ORDER": 10,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "New_Rate",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": false,
                    "DISPLAY_NAME": this.$t('New Rate'),
                    "DISPLAY_ORDER": 11,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "New_Start_Date",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": false,
                    "DISPLAY_NAME": this.$t('New Start Date'),
                    "DISPLAY_ORDER": 12,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "New_End_Date",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": false,
                    "DISPLAY_NAME": this.$t('New End Date'),
                    "DISPLAY_ORDER": 13,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "CREATED_AT",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Created AT',
                    "DISPLAY_ORDER": 10,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "CREATED_BY",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Created By',
                    "DISPLAY_ORDER": 11,
                },
                {
                    "COLUMN_NAME": "MODIFIED_BY",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Modified By',
                    "DISPLAY_ORDER": 12,
                },
                {
                    "COLUMN_NAME": "MODIFIED_AT",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Modified Date',
                    "DISPLAY_ORDER": 13,
                    settings: {
                        isInSlot: true
                    }
                }
            ],
            SortBy: '',
            SortExp: '',
            PageSize: 10,
            PageNumber: 1,
            TotalRecords: 0,
            CurrentPage: 1,
            TotalPages: 0,
            noRecords: false,
            searchCondition: '',
            RateScheduleData: [],
            RateScheduleDataExcel: [],
            listheaderbuttons: Schema.buttons,
            listActions: Schema.listActions,
            leftSearchFields:  JSON.parse(JSON.stringify(Schema.leftsearchSchema)),
            CompanyId: null,
            UserId: null,
            searchBy: '',
            search: '',
            isShowAddRate: false,
            isBulkUpdateRate: false,
            EditData: [],
            EditDataCopy: [],
            clientId: '',
            clientList: [],
            SelectedUtilityList: [],
            Searchparms: '',
            isSupervisor: false,
            privilegeParams: '',
        }
    },
    created: async function () {
        var vm = this;
        vm.UpdateRecord = false;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.CompanyId = this.GetUserInfo.CompanyId;
        vm.UserId = this.GetUserInfo.ID;
        vm.privilegeParams = `controller=RateSchedule&action=`;
        await vm.BindSupervisor();
        await vm.GetEmailConfigurationSetting();
        await vm.fetchclientlist();
        vm.leftSearchFields.find(f => f.fieldName === 'Contract').onChange = this.onSelectionChange;
        
        Schema.bindleftCommonSearchdropdown(this, 'WORKCODE');
        Schema.bindleftCommonSearchdropdown(this, 'STATE');
        Schema.bindleftCommonSearchdropdown(this, "BILLER");
        
        await vm.FetchData();

    },
    methods: {
        fetchclientlist: async function () {
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOM`;
            try {
                const response = await locateBillingService.getClientList(url);
                vm.clientList = response.data.items || [];
                vm.leftSearchFields.find(f => f.fieldName === 'Contract').value = "";
                vm.leftSearchFields.find(f => f.fieldName === 'Contract').listOptions = vm.clientList;
            } catch (error) {
                vm.clientList = [];
                vm.leftSearchFields.find(f => f.fieldName === 'Contract').listOptions = [];
                console.error('Error fetching client list:', error);
            } finally {
                vm.isLoading = false;
            }
        },
        openSelectedRecords(payload) {
            debugger;

            const vm = this;

            vm.isCopyRate = false;
            vm.isShownCopyButton = true;
            vm.UpdateRecord = true;

            if (!vm.selectedRateIds || payload.ids.length > 1) {
                // First time OR bulk edit → set selection
                vm.selectedRateIds = payload.ids.map(Number);
            }
            
            vm.EditDataCopy =
                payload.ids.length === 1
                    ? vm.RateScheduleData.find(
                        r => r.RATE_SCHEDULE_ID === payload.ids[0]
                    )
                    : null;

            vm.resetNewHeaders();

            if (payload.action === 'UPDATE_END_DATE') {
                vm.Headers.forEach(col => {
                    if (
                        col.COLUMN_NAME === "New_Start_Date" ||
                        col.COLUMN_NAME === "New_End_Date" ||
                        col.COLUMN_NAME === "New_Rate" ||
                       // col.COLUMN_NAME === "comment" ||
                        col.COLUMN_NAME === "New_Customer_Work_Code"
                    ) {
                        col.VISIBLE = true;
                    }
                });
            }

            vm.RateScheduleData.forEach(row => {
                if (payload.ids.includes(row.RATE_SCHEDULE_ID)) {
                    row.New_Start_Date = payload.newStartDate
                        ? vm.$options.filters.formatDate(payload.newStartDate)
                        : '--';

                    row.New_End_Date = payload.newEndDate
                        ? vm.$options.filters.formatDate(payload.newEndDate)
                        : '--';

                    row.New_Rate = row.AMOUNT;
                    row.New_Customer_Work_Code = row.Billing_Code;
                    row.action = payload.action || null;
                }
            });

            vm.refreshKey++;
            
            vm.$nextTick(() => {
                setTimeout(() => {
                    $('.left-search, .tg-left-search, .search-panel').hide();
                    $('table tbody tr').hide();

                    vm.leftSearchFields = [];
                    vm.TotalRecords = [];

                    // 🔥 IMPORTANT: use selectedRateIds (NOT payload.ids)
                    $('.chkItems:checkbox').each(function () {
                        const id = Number($(this).val());
                        if (vm.selectedRateIds.includes(id)) {
                            const row = $(this).closest('tr');
                            row.show();
                            row[0].scrollIntoView({
                                behavior: 'smooth',
                                block: 'center'
                            });
                        }
                    });
                }, 150);
            });
        },



        resetNewHeaders() {
            this.Headers.forEach(col => {
                if (
                    col.COLUMN_NAME === "New_Start_Date" ||
                    col.COLUMN_NAME === "New_End_Date" ||
                    col.COLUMN_NAME === "New_Rate" ||
                    //col.COLUMN_NAME === "comment" ||
                    col.COLUMN_NAME === "New_Customer_Work_Code"
                ) {
                    col.VISIBLE = false;
                }
            });
        },

        onSelectionChange(value, x) {
            debugger
            var vm = this;
            vm.isLoading = true;
            if (x == null) {
                vm.leftSearchFields.find(f => f.fieldName === 'UtilityName').listOptions = [];
            }
            vm.selectedId = x;
            var url = `clientId=${x}&configId=&reqFrom=&clientIds=`;
            locateBillingService.getUtilityList(url).then(response => {
                vm.isLoading = false;
                let SelectedUtilityList = [];
                var UtilityList = response.data;
                if (UtilityList != null && UtilityList.length > 0) {
                    UtilityList.forEach(item => {
                        let obj = {
                            name: item.UTILITY_NAME,
                            value: item.UTILITY_NAME
                        };
                        SelectedUtilityList.push(obj);
                    });
                    vm.leftSearchFields.find(f => f.fieldName === 'UtilityName').listOptions = SelectedUtilityList;
                } else {
                    vm.leftSearchFields.find(f => f.fieldName === 'UtilityName').listOptions = [];
                }
            }).catch(error => {
                vm.isLoading = false;
                vm.leftSearchFields.find(f => f.fieldName === 'UtilityName').listOptions = [];
            }).finally(() => {
                vm.isLoading = false;
            });
        },

        actionButtonClick: function (callbackfunction, item) {
            var vm=this;
            switch (callbackfunction) {
                case "Edit":
                     DataService.CheckPrivilege(vm.privilegeParams+'EditRate').then((response)=>{
                        if(response.data){
                            this.EditAddRate(item.RATE_SCHEDULE_ID);
                        }
                        else{
                            vm.ShowAlert(vm.$t('UnAuthorized'), "warning", true, "Alert");
                            return false;
                        }
                    });                   
                    break;
            }
        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                if (value.searchConditionJson != '') {
                    const fvalue = value.searchConditionJson.split('=')[1];
                    this.Searchparms = fvalue;
                } else {
                    this.Searchparms = '';
                    this.searchCondition = value.searchCondition;
                }
            } else {
                this.Searchparms = '';
                this.searchCondition = "";
            }
            this.FetchData();
        },
        commonHeaderButtonClick: function (event) {
            var vm = this;
            switch (event.callbackfunction) {
                case "Inactive":
                    this.UpdataStatus(1002, '');
                    break;
                case "AddRateSchedule":
                     DataService.CheckPrivilege(vm.privilegeParams+'AddRate').then((response)=>{
                        if(response.data){
                             this.AddRateSchedule();
                        }
                        else{
                            vm.ShowAlert(vm.$t('UnAuthorized'), "warning", true, "Alert");
                            return false;
                        }
                    });                  
                    break;
                case "Update":
                    this.BulkUpdateRate();
                    break;
                case "CopyRate":
                       DataService.CheckPrivilege(vm.privilegeParams+'UpdateRates').then((response)=>{
                        if(response.data){
                           this.CopyRate();
                        }
                        else{
                            vm.ShowAlert(vm.$t('UnAuthorized'), "warning", true, "Alert");
                            return false;
                        }
                    });                    
                    break;
                case "ExportToExcel":
                    this.ExportToExcel();
                    break;
                case "ViewHistory":
                    DataService.CheckPrivilege(vm.privilegeParams+'RateScheduleHistory').then((response)=>{
                        if(response.data){
                          this.ViewHistory();
                        }
                        else{
                            vm.ShowAlert(vm.$t('UnAuthorized'), "warning", true, "Alert");
                            return false;
                        }
                    });                    
                    break;
                case "commonDeleteData":
                    this.commonDeleteData();
                    break;
            }
        },
        UpdateCopyRateSchedule() {
            debugger;
            var vm=this;
            if (!this.selectedRateIds || this.selectedRateIds.length === 0) {
                this.ShowAlert(this.$t("PleaseSelectAnyRecordsForFurther"), "warning", true, this.$t("Alert"));
                return;
            }
            const selectedRows = this.RateScheduleData.filter(x =>
                this.selectedRateIds.includes(x.RATE_SCHEDULE_ID)
            );
            const utilityNames = [...new Set(selectedRows.map(row => row.UTILITY_NAME))];
            
            const jsonPayload = selectedRows.map(row => ({
                RateScheduleId: row.RATE_SCHEDULE_ID,
                ClientId: row.CLIENT_ID,
                WorkCodeId: row.WORKCODE_ID,
                UtilityId: row.UTILITY_ID,
                State: row.STATE_CODE,
                StartDate: row.New_Start_Date,
                EndDate: row.New_End_Date,
                Rate: row.New_Rate,
                //Comment: row.COMMENT || "",  
                Notes: row.NOTES || "",
                StatusId: row.STATUS_ID,
                optionselected: row.action,
                BillingCode:row.New_Customer_Work_Code,
                // OriginalStartDate: row.START_DATE,
                // OriginalEndDate: row.END_DATE,
                // OriginalRate: row.AMOUNT || row.RATE
            }));
            
            const params = {
                jsonString: JSON.stringify(jsonPayload),
                optionselected: jsonPayload[0].optionselected
            };
            this.isLoading = true;

            DataService.UpdateRates(params).then(res => {
                    this.isLoading = false;
                    if (res && res.data) {
                        if (res.data.result === '1') {                            
                             vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('RateSchedule')]), "success", true, vm.$t("Alert"));
                            vm.selectedRateIds = [];
                            vm.UpdateRecord=false;
                            vm.EditDataCopy=[]; 
                            vm.isShownCopyButton = false;
                            vm.resetNewHeaders();
                            vm.Cancel();
                        } else if (res.data.result === '-3') {
                            const utilityList = utilityNames.join(', ');
                            this.ShowAlert(`Rate for utilities already exists please change the date range for following utilities: ${utilityList}`,
                                "alert-danger", true, "Date Overlap");
                        } else if (res.data.result === '-2') {
                            this.ShowAlert(res.data.msg || "Rate for utilities already exists. Please change date range.",
                                "warning", true, "Utility Overlap");
                        } else {
                            this.ShowAlert(res.data.msg || this.$t("UnknownError"), "failure", true, this.$t("Alert"));
                        }
                    } else {
                        this.ShowAlert(this.$t("UnknownError"), "failure", true, this.$t("Alert"));
                    }
                })
                .catch(error => {
                    this.isLoading = false;
                    this.ShowAlert(this.$t("UnknownError"), "failure", true, this.$t("Alert"));
                });
        },
        Cancel() {
            window.location.href = window.location.href;
        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                if (value.searchConditionJson != '') {
                    const fvalue = value.searchConditionJson.split('=')[1];
                    this.Searchparms = fvalue;
                } else {
                    this.Searchparms = '';
                    this.searchCondition = value.searchCondition;
                }
            } else {
                this.Searchparms = '';
                this.searchCondition = "";
            }
            this.FetchData();
        },
        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "Inactive":
                    this.UpdataStatus(1002, '');
                    break;
                case "AddRateSchedule":
                    this.AddRateSchedule();
                    break;
                case "Update":
                    this.BulkUpdateRate();
                    break;
                case "CopyRate":
                    this.CopyRate();
                    break;
                case "ExportToExcel":
                    this.ExportToExcel();
                    break;
                case "ViewHistory":
                    this.ViewHistory();
                    break;
                case "commonDeleteData":
                    this.commonDeleteData();
                    break;
            }
        },
        CopyRate() {
            var vm = this;
            var val = "";
            $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(async function () {
                if (val.length > 0) {
                    val += ',';
                }
                val += $(this).val();
            });
            let ids = val.split(',').map(Number);
            if (val.length > 0) {
                // PRIVILEGE-CHECK: RateSchedule / UpdateRates (added for CopyRate modal)
                var privilegeParams = `controller=RateSchedule&action=UpdateRates`;
                DataService.CheckPrivilege(privilegeParams).then(function (response) {
                    if (response.data) {
                        vm.EditData = vm.RateScheduleData.filter(x => ids.includes(x.RATE_SCHEDULE_ID));
                        vm.isCopyRate = true;
                    } else {
                        vm.ShowAlert(vm.$t('NotAuthorizedSection'), "failure", true, "Alert");
                    }
                });
            } else {
                vm.ShowAlert(vm.$t("PleaseSelectAnyRecordsForFurther"), "warning", true, vm.$t("Alert"));
            }

        },
        BulkUpdateRate() {
            var vm = this;
            var val = "";
            $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(async function () {
                if (val.length > 0) {
                    val += ',';
                }
                val += $(this).val();
            });
            let ids = val.split(',').map(Number);
            if (val.length > 0) {
                // PRIVILEGE-CHECK: RateSchedule / UpdateRates (added for BulkUpdateRate modal)
                var privilegeParams = `controller=RateSchedule&action=UpdateRates`;
                DataService.CheckPrivilege(privilegeParams).then(function (response) {
                    if (response.data) {
                        vm.EditData = vm.RateScheduleData.filter(x => ids.includes(x.RATE_SCHEDULE_ID));
                        vm.isBulkUpdateRate = true;
                    } else {
                        vm.ShowAlert(vm.$t('NotAuthorizedSection'), "failure", true, "Alert");
                    }
                });
            } else {
                vm.ShowAlert(vm.$t("PleaseSelectAnyRecordsForFurther"), "warning", true, vm.$t("Alert"));
            }
        },
        AddRateSchedule() {
            var vm = this;
            vm.EditData = [];
            // PRIVILEGE-CHECK: RateSchedule / AddRate (added for AddRateSchedule modal)
            var privilegeParams = `controller=RateSchedule&action=AddRate`;
            DataService.CheckPrivilege(privilegeParams).then(function (response) {
                if (response.data) {
                    vm.isShowAddRate = true;
                } else {
                    vm.ShowAlert(vm.$t('NotAuthorizedSection'), "failure", true, "Alert");
                }
            });
        },
        sortdata: function (sortBy) {
            this.SortBy = sortBy;
            var sortExp = 'ASC';
            if (this.SortExp == 'ASC') {
                sortExp = 'DESC';
            }
            this.SortExp = sortExp;
            this.SortBy = sortBy;
            this.SortExp = sortExp;
            this.PageNumber = 1;
            this.FetchData();
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = {
                    ...actionItem
                };
                switch (action.title) {
                    case 'Edit':
                        action.isVisible = true;
                        break;
                    default: {
                        action.isVisible = true;
                    }
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        FetchData: async function () {
            var vm = this;
            vm.UpdateRecord = false;
            var params = '';
            vm.isLoading = true;
            var params = `clientId=${vm.clientId}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&pageNum=${vm.PageNumber}&pageSize=${vm.PageSize}&Search=${vm.searchCondition}&userDate=${Date.now()}&BillerIds=${vm.Searchparms}`
            await DataService.GetRateSechduleList(params).then((response) => {
                if (response.data.result.length > 0) {
                    debugger;
                    vm.isLoading = false;
                    vm.RateScheduleData = JSON.parse(response.data.result);
                    vm.TotalRecords = vm.RateScheduleData[0].TOTAL_RECORDS;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                    vm.CurrentPage = vm.PageNumber;
                    vm.noRecords = false;
                } else {
                    vm.RateScheduleData = [];
                    vm.noRecords = true;
                    vm.TotalRecords = 0
                    vm.isLoading = false;
                }
            })
        },
        UpdataStatus(StatusID, ID) {
            var vm = this;
             DataService.CheckPrivilege(vm.privilegeParams+'UpdateStatus').then((response)=>{                
                   if(response.data){                 
                       var val = "";
                       $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(async function () {
                           if (val.length > 0) {
                               val += ',';
                           }
                           val += $(this).val();
                       });
                       // PRIVILEGE-CHECK: RateSchedule / UpdateStatus (added)
                       var privilegeParams = `controller=RateSchedule&action=UpdateStatus`;
                       DataService.CheckPrivilege(privilegeParams).then(function (response) {
                           if (response.data) {
                               vm.confirmR(vm.$t('ChanggingActivetoInactive'), true, false, function (result) {
                                   var postJSON = {
                                       ID: val || ID,
                                       StatusId: StatusID,
                                       IsFor: "TALYGEN_BE_RATE_SCHEDULE",
                                       Module: "RateSchedule",
                                       Submodule: "Rate Schedule",
                                   };
                                   var objectPostString = JSON.stringify(postJSON);
                                   DataService.CommonUpdateStatus(objectPostString).then(async response => {
                                       if (response.status == 200) {
                                           $('.chkItems:checkbox:checked').prop("checked", false).removeAttr('checked');
                                           vm.listheaderbuttons[0].isdisabled = true;
                                           vm.ShowAlert(vm.$t('RecordUpdatedSuccessfully'), "success", true, vm.$t("Alert"));
                                           vm.FetchData();
                                       }
                                   });
                               })
                           } else {
                               vm.ShowAlert(vm.$t('NotAuthorizedSection'), "failure", true, "Alert");
                           }
                       });
                   }
                   else{
                       vm.ShowAlert(vm.$t('UnAuthorized'), "warning", true, "Alert");
                       return false;
                   }
               });
        },
        commonDeleteData: function (id) {
            var vm = this;
            var val = "";
            vm.isLoading = true;
            if (id == null) {
                $('.chkItems:checkbox:checked').not("[id^='chkAll_0']").each(function () {
                    if (val.length > 0)
                        val += ',';
                    val += $(this).val();
                });
            } else {
                val = id;
            }
            if (val != null) {
                // PRIVILEGE-CHECK: RateSchedule / Delete (added)
                var privilegeParams = `controller=RateSchedule&action=Delete`;
                DataService.CheckPrivilege(privilegeParams).then(function (response) {
                    if (response.data) {
                        vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("RateSchedule")), function () {
                            var url = `ids=${val}&tablename=TALYGEN_BE_RATE_SCHEDULE&primaryKey=RATE_SCHEDULE_ID`;
                            DataService.Delete(url).then(function (response) {
                                if (response.status == 200) {
                                    vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('RateSchedule')]), "success", true, vm.$t("Alert"));
                                    vm.FetchData();
                                } else {
                                    vm.ShowAlert(vm.$t('DeletedError', [vm.$t('RateSchedule')]), "Success", true, vm.$t("Alert"));
                                }
                            });
                        });
                    } else {
                        vm.ShowAlert(vm.$t('NotAuthorizedSection'), "failure", true, "Alert");
                    }
                });
            } else {
                vm.ShowAlert(vm.$t("Selectanyrecordtodelete"));
            }
            vm.isLoading = false;
        },
        EditAddRate(id) {
            debugger;
            var vm = this;
            if (vm.UpdateRecord) {
                vm.EditDataCopy = vm.RateScheduleData.find(row => row.RATE_SCHEDULE_ID === Number(id));                
                vm.isCopyRate = true;
            } else {
                var vm = this;
                vm.EditData = vm.RateScheduleData.find(x => x.RATE_SCHEDULE_ID === id);
                vm.isShowAddRate = true;
            }
        },
        ViewHistory() {
            var vm = this;
            this.$router.push({
                name: 'RateScheduleHistory'
            });
        },

        onSubmit() {
            const vm = this;
            if (vm.RateScheduleData.length === 1) {
                const row = vm.RateScheduleData[0];

                // ✅ payload object (NOT a function)
                const payload = {
                    RateScheduleId: row.RATE_SCHEDULE_ID,
                    ClientId: row.CLIENT_ID,
                    UtilityId: row.UTILITY_ID,
                    WorkCodeId: row.WORKCODE_ID,
                    Rate: row.AMOUNT,
                    StartDate: row.START_DATE,
                    EndDate: row.END_DATE,
                    Comment: row.COMMENT,
                    BillingCode: row.Billing_Code,
                    optionselected: row.optionselected,

                    // extra fields (safe for OPENJSON)
                    State: row.STATE_CODE,
                    Notes: row.NOTES,
                    StatusId: row.STATUS_ID,
                    CreatedBy: row.CREATED_BY,
                    CreatedAt: row.CREATED_AT,
                    ModifiedBy: row.MODIFIED_BY,
                    ModifiedDate: row.MODIFIED_AT,
                    UtilityName: row.UTILITY_NAME,
                    ClientName: row.CLIENT_NAME,
                    WorkCode: row.WORK_CODE,
                    Status: row.STATUS
                };

                DataService.UpdateRateSchedule(payload).then(response => {
                    if (!response.data) return;
                    const result = response.data.RESULT??JSON.parse(response.data)[0]?.RESULT;
                    if (parseInt(result) === 1) {
                        vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('RateSchedule')]), "success", true, vm.$t('Alert'));
                        vm.FetchData();
                    } else {
                        vm.ShowAlert(vm.$t("UnknownError"), "failure", vm.$t('Alert'));
                    }
                });
            }
        },

        BindSupervisor: function () {
            var vm = this;
            DataService.CheckIsSupervisor().then(response => {
                if (response.data) {
                    vm.isSupervisor = response.data;
                }
            });
        },

        GetEmailConfigurationSetting() {
            var vm = this;
            var params = `_CompanyId=${vm.CompanyId}&userId=${vm.UserId}&moduleName=User&configkey=CanViewAllContractData`;
            DataService.GetEmailConfigurationSetting(params)
                .then(response => {
                    if (response.data && response.data.length > 0) {
                        if (response.data[0].CONFIG_DATA_VALUE.toLowerCase() === 'yes' || vm.UserType.toLowerCase() == 'ca' || vm.isSupervisor) {
                            Schema.bindleftCommonSearchdropdown(this, "BILLER");
                        } else {
                            vm.leftSearchFields = vm.leftSearchFields.filter((_, index) => index !== 4);
                        }
                    }
                })
                .catch(err => {
                    console.log(err);
                });
        },

       async ExportToExcel() {
            debugger;
            const vm = this;
            vm.isLoading = true;
            // PRIVILEGE-CHECK: RateSchedule / ExportToExcel (added)
            var privilegeParams = `controller=RateSchedule&action=ExportToExcel`;
            const privilegeRes = await DataService.CheckPrivilege(privilegeParams);
            if (!privilegeRes || !privilegeRes.data) {
                vm.isLoading = false;
                vm.ShowAlert(vm.$t('NotAuthorizedSection'), "failure", true, "Alert");
                return;
            }
            await vm.FetchDataExport();
          
            // Template with correct column order
            const objTemplate = {
                'Id': '',
                'Client': '',
                'Work Code': '',
                'Utility Name': '',
                'Customer Work Code': '',
                'Rate': '',
                'Status': '',
                'Start Date': '',
                'End Date': '',
                'Created By': '',
                'Created Date': '',
                'Modified By': '',
                'Modified Date': '',
                'State': ''
            };

            const dataArray = [];

            try {
                const RateScheduleArray = vm.RateScheduleDataExcel || [];

                RateScheduleArray.forEach(item => {
                    const newObj = { ...objTemplate };

                    newObj['Id'] = item.RATE_SCHEDULE_ID || '';
                    newObj['Client'] = item.CLIENT_NAME || '';
                    newObj['Work Code'] = item.WORK_CODE || '';
                    newObj['Utility Name'] = item.UTILITY_NAME || '';
                    newObj['Customer Work Code'] = item.CUSTOMER_WORK_CODE || '';
                    newObj['Rate'] = item.AMOUNT || '';
                    newObj['Status'] = item.STATUS || '';
                    newObj['Start Date'] = item.START_DATE || '';
                    newObj['End Date'] = item.END_DATE || '';
                    newObj['Created By'] = item.CREATED_BY || '';
                    newObj['Created Date'] = item.CREATED_AT || '';
                    newObj['Modified By'] = item.MODIFIED_BY || '';
                    newObj['Modified Date'] = item.MODIFIED_AT || '';
                    newObj['State'] = item.STATE_NAME || '';

                    dataArray.push(newObj);
                });

            } catch (e) {
                console.error("Error while preparing Excel data:", e);
            }

            if (dataArray.length > 0) {
                const worksheet = XLSX.utils.json_to_sheet([]);
                const workbook = XLSX.utils.book_new();
                const currentDateTime = new Date().toLocaleString('en-US');
                const titleRow = [
                    ['RateScheduleExport', '', '', '', currentDateTime]
                ];
                XLSX.utils.sheet_add_aoa(worksheet, titleRow, {
                    origin: 'A1'
                });
                worksheet['!merges'] = [{
                    s: {
                        r: 0,
                        c: 0
                    },
                    e: {
                        r: 0,
                        c: 3
                    }
                }];
                worksheet['A1'].s = {
                    font: {
                        bold: true,
                        size: 20,
                        color: {
                            rgb: "000000"
                        }
                    },
                    alignment: {
                        horizontal: "left"
                    },
                };
                worksheet['E1'].s = {
                    font: {
                        bold: true,
                        size: 20,
                        color: {
                            rgb: "000000"
                        }
                    },
                    alignment: {
                        horizontal: "left"
                    },
                };
                const header = Object.keys(dataArray[0]);
                XLSX.utils.sheet_add_aoa(worksheet, [header], {
                    origin: 'A2'
                });
                XLSX.utils.sheet_add_json(worksheet, dataArray, {
                    origin: 'A3',
                    skipHeader: true
                });
                const range = XLSX.utils.decode_range(worksheet['!ref']);
                for (let C = range.s.c; C <= range.e.c; ++C) {
                    const cell_address = XLSX.utils.encode_cell({
                        c: C,
                        r: 1
                    });
                    if (!worksheet[cell_address]) continue;
                    worksheet[cell_address].s = {
                        font: {
                            bold: true,
                            size: 18,
                            color: {
                                rgb: "000000"
                            }
                        },
                        fill: {
                            fgColor: {
                                rgb: "D3D3D3"
                            }
                        },
                        alignment: {
                            horizontal: "left"
                        },
                    };
                }
                const colWidths = header.map(col => ({
                    wpx: Math.max(
                        col.length * 10,
                        ...dataArray.map(row => (row[col] || '').toString().length * 10)
                    )
                }));
                worksheet['!cols'] = colWidths;
                XLSX.utils.book_append_sheet(workbook, worksheet, "RateScheduleExport.");
                XLSX.writeFile(workbook, "RateScheduleExport.xlsx");
            } else {
                console.error("No data available to export");
            }
            vm.isLoading = false;
        },

          FetchDataExport: async function () {
            var vm = this;
            vm.UpdateRecord = false;
            var params = '';
            vm.isLoading = true;
            var params = `clientId=${vm.clientId}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&pageNum=${vm.PageNumber}&pageSize=${vm.TotalRecords}&Search=${vm.searchCondition}&userDate=${Date.now()}&BillerIds=${vm.Searchparms}`
            await DataService.GetRateSechduleList(params).then((response) => {
                if (response.data.result.length > 0) {
                    vm.isLoading = false;
                    vm.RateScheduleDataExcel = JSON.parse(response.data.result);                    
                } else {
                    vm.RateScheduleDataExcel = [];
                    vm.isLoading = false;
                }
            })
        },
    }
}
