<template lang="en">
<div class="my-popups">
    <loader :is-visible="isLoading"></loader>

    <div class="modal d-block">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">

                <div class="modal-header theme-primary partition-full d-flex">
                    <h4 class="modal-title">{{ $t('SetDates') }}</h4>
                    <button type="button" class="close" @click="Close()">
                        <em class="fa fa-times"></em>
                    </button>
                </div>

                <div class="modal-body">
                    <dynamic-form ref="ResourceRate" :schema="FormSchema" :buttons="buttons" :mandatorytext="MandatoryString" @OnSubmit="onSubmit" />
                </div>

            </div>
        </div>
    </div>
</div>
</template>

<script>
export default {
    props: {
        EditData:{ 
            type:Array,
            required: true,
        },
        EditDataCopy: {
          type: Array,
          required: false,
        }
    },

    data() {
        return {
            isLoading: false,
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            companyId: null,
            userId: null,
            selectedRadio: 1, // 1 for first radio, 2 for second radio

            FormSchema: [{
                    layoutType: "double",
                    Data: [{
                            astype: "DateField",
                            label: this.$t('Start Date (M/D/YYYY)'),
                            name: "StartDate",
                            value: new Date(),
                            config: {
                                format: "MM/DD/YYYY",
                                onChange: this.onStartDateChange
                            },
                            validationRules: {
                                required: true
                            }
                        },

                        {
                            astype: "DateField",
                            label: this.$t('End Date (M/D/YYYY)'),
                            name: "EndDate",
                            value: '',
                            config: {
                                format: "MM/DD/YYYY",
                            },
                            validationRules: {
                                required: true
                            }
                        },

                        {
                            astype: "RadioField",
                            label: '',
                            name: "radio1",
                            value: true,
                            config: {
                                options: [{
                                    value: true,
                                    name: ''
                                }],
                                onChange: () => this.handleRadioChange(1)
                            }
                        },
                        {
                            astype: "RadioField",
                            label: '',
                            name: "radio2",
                            value: false,
                            config: {
                                options: [{
                                    value: true,
                                    name: this.$t('Do you want to mark previous Records as Inactive?')
                                }],
                                onChange: () => this.handleRadioChange(2)
                            }
                        }
                    ]
                },

                {
                    layoutType: "single",
                    Data: [{
                        astype: "TextAreaField",
                        label: this.$t('Comment'),
                        name: "Comment",
                        value: "",
                        placeholder: this.$t('Enter Comment')
                    }]
                }
            ],

            buttons: [{
                type: "submit",
                class: "btn btn-success",
                text: "<i class='fa fa-save pr-2'></i>Set New Dates",
                isVisible: true
            }]
        };
    },

    created() {
        debugger;
        var vm=this;        
        this.userId = this.GetUserInfo.ID;
        this.companyId = this.GetUserInfo.CompanyId;
        this.updateRadioText(new Date());

        if (vm.EditDataCopy?.action) {
            vm.EditDataCopy.action=='UPDATE_END_DATE'? this.handleRadioChange(1): this.handleRadioChange(2);      
            vm.FormSchema[0].Data[0].value = new Date(vm.EditDataCopy.New_Start_Date) || '';
            vm.FormSchema[0].Data[1].value = new Date(vm.EditDataCopy.New_End_Date) || '';
            vm.FormSchema[0].Data[2].visibility=false;
            vm.FormSchema[0].Data[3].visibility=false;
            vm.FormSchema[1].Data[0].visibility=false;
        }
    },

    methods: {
        getPreviousDate(date) {
            const d = new Date(date);
            d.setDate(d.getDate() - 1);
            return d.toLocaleDateString('en-US');
        },

        updateRadioText(startDate) {
            const prevDate = this.getPreviousDate(startDate);
            this.FormSchema[0].Data[2].config.options[0].name =
                `${this.$t('Previous records End Date will be updated as:')} ${prevDate}`;
        },

        onStartDateChange(value) {
            this.updateRadioText(value);
        },

        // This method handles radio button selection
        handleRadioChange(radioNumber) {
            this.selectedRadio = radioNumber;

            // Update radio values based on selection
            if (radioNumber === 1) {
                // Select first radio, deselect second
                this.FormSchema[0].Data[2].value = true;
                this.FormSchema[0].Data[3].value = false;
            } else {
                // Select second radio, deselect first
                this.FormSchema[0].Data[2].value = false;
                this.FormSchema[0].Data[3].value = true;
            }

            // Force update the form
            if (this.$refs.ResourceRate) {
                this.$refs.ResourceRate.$forceUpdate();
            }
        },

        getSelectedAction() {
            return this.selectedRadio === 1 ?
                'UPDATE_END_DATE' :
                'MARK_AS_INACTIVE';
        },

        onSubmit(formfields) {
            debugger
            if (!this.$refs.ResourceRate.validateForm.validate()) return;

            if (formfields.StartDate && formfields.EndDate) {
                const startDate = new Date(formfields.StartDate);
                const endDate = new Date(formfields.EndDate);

                // Check 1: Start Date should be less than End Date
                if (startDate >= endDate) {
                    this.ShowAlert("Start Date should be less than End Date.","warning",true,"Validation Error");
                    return;
                }
                if (endDate <= startDate) {
                    this.ShowAlert("End Date Should be earlier than Start Date.","warning",true,"Validation Error");
                    return;
                }
            }

            const isSingleEdit =
                this.EditDataCopy &&
                this.EditDataCopy.RATE_SCHEDULE_ID != null;

            const payload = {
                ids: isSingleEdit
                    ? [this.EditDataCopy.RATE_SCHEDULE_ID] // ✅ only matching record
                    : this.EditData.map(x => x.RATE_SCHEDULE_ID),

                newStartDate: formfields.StartDate,
                newEndDate: formfields.EndDate,
                action: this.getSelectedAction(),
                comment: formfields.Comment || ''
            };


            this.$emit("navigateToSelected", payload);
            
        },

        Close: function () {
            this.$parent.isCopyRate = false;
        }
    }
};
</script>
